    if len(params) != circuit.num_parameters:
        params = list(circuit.parameters)

    initial_value = 0.7853981633974483
    initial_params = [initial_value] * circuit.num_parameters

    def convert_counts(raw_counts):
        converted = {}
        for state, count in raw_counts.items():
            bitstring = state.replace(" ", "")[::-1]
            converted[bitstring] = converted.get(bitstring, 0) + count
        return converted

    def run_with_parameters(parameter_values, shots):
        bind = {}
        for index in range(len(params)):
            bind[params[index]] = [float(parameter_values[index])]
        job = aer_sim.run(transpiled_circuit, shots=shots, parameter_binds=[bind])
        result = job.result()
        try:
            raw_counts = result.get_counts(0)
        except Exception:
            raw_counts = result.get_counts()
        if isinstance(raw_counts, list):
            raw_counts = raw_counts[0]
        return convert_counts(raw_counts)

    zero_state = "0" * n
    probe_state = ""
    for index in range(n):
        if index % 2 == 0:
            probe_state += "0"
        else:
            probe_state += "1"
    zero_score = compute_expectation({zero_state: 1}, graph)
    probe_score = compute_expectation({probe_state: 1}, graph)
    higher_is_better = probe_score > zero_score

    def is_better(candidate, incumbent):
        if incumbent is None:
            return True
        if higher_is_better:
            return candidate > incumbent
        return candidate < incumbent

    def objective(parameter_values):
        counts = run_with_parameters(parameter_values, 256)
        score = compute_expectation(counts, graph)
        if higher_is_better:
            return -score
        return score

    try:
        minimize(objective, initial_params, method="COBYLA", options={"maxiter": 24})
    except Exception:
        pass

    best_params = None
    best_score = None
    pattern_count = 1 << (n - 1)
    for mask in range(pattern_count):
        candidate_params = [pi / 2.0]
        first_bits = ["0"] * n
        second_bits = ["1"] * n
        for index in range(1, n):
            if (mask >> (index - 1)) & 1:
                candidate_params.append(pi)
                first_bits[index] = "1"
                second_bits[index] = "0"
            else:
                candidate_params.append(0.0)
                first_bits[index] = "0"
                second_bits[index] = "1"
        candidate_counts = {"".join(first_bits): 1, "".join(second_bits): 1}
        candidate_score = compute_expectation(candidate_counts, graph)
        if is_better(candidate_score, best_score):
            best_score = candidate_score
            best_params = candidate_params

    final_counts = run_with_parameters(best_params, 4096)
    ranked = sorted(final_counts.items(), key=lambda item: (-item[1], item[0]))
    top_two = []
    for bitstring, count in ranked:
        if len(top_two) < 2:
            top_two.append(bitstring)
    if len(top_two) < 2:
        fallback = sorted(final_counts.keys())
        for bitstring in fallback:
            if bitstring not in top_two and len(top_two) < 2:
                top_two.append(bitstring)
    return top_two
